#define BLOCK_SIZE 16

__attribute__((reqd_work_group_size(BLOCK_SIZE, 1, 1)))
void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i, j, k;
    int local_id = get_local_id(0);

    for (i = 0; i < BLOCK_SIZE; i++) {
        if (i == local_id) {
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
                }
                a[(offset + i) * size + (offset + j)] -= sum;
            }

            float diag = a[(offset + i) * size + (offset + i)];
            float temp_val = 1.0f / diag;

            for (j = i + 1; j < BLOCK_SIZE; j++) {
                float sum_col = 0.0f;
                for (k = 0; k < i; k++) {
                    sum_col += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
                }
                a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum_col) * temp_val;
            }
        }
    }
}

__attribute__((reqd_work_group_size(BLOCK_SIZE * 2, 1, 1)))
void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_diag, const int size, const int offset)
{
    int chunk_idx = get_local_id(0);
    int i, j, k;
    int i_global, j_global;
    float sum;

    if (chunk_idx < BLOCK_SIZE) {
        int i_local = chunk_idx;
        j_global = offset + BLOCK_SIZE * (1 + 0); 

        for (j = 0; j < BLOCK_SIZE; j++) {
            sum = 0.0f;
            for (k = 0; k < i_local; k++) {
                sum += temp_diag[i_local * BLOCK_SIZE + k] * a[(offset + k) * size + (j_global + j)];
            }
            a[(offset + i_local) * size + (j_global + j)] -= sum;
        }
    } else {
        int j_local = chunk_idx - BLOCK_SIZE;
        i_global = offset + BLOCK_SIZE * (1 + 0);

        for (i = 0; i < BLOCK_SIZE; i++) {
            sum = 0.0f;
            for (k = 0; k < j_local; k++) {
                sum += a[(i_global + i) * size + (offset + k)] * temp_diag[k * BLOCK_SIZE + j_local];
            }
            int idx = (i_global + i) * size + (offset + j_local);
            a[idx] = (a[idx] - sum) / a[(offset + j_local) * size + (offset + j_local)];
        }
    }
}

__attribute__((reqd_work_group_size(BLOCK_SIZE, BLOCK_SIZE, 1)))
void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int chunk_row = get_group_id(0);
    int chunk_col = get_group_id(1);
    int i = get_local_id(0);
    int j = get_local_id(1);
    int k;

    int i_global = offset + BLOCK_SIZE * (1 + chunk_row);
    int j_global = offset + BLOCK_SIZE * (1 + chunk_col);

    float sum = 0.0f;

    for (k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
    }

    a[(i_global + i) * size + (j_global + j)] -= sum;
}
